mapper.select:
SELECT DISTINCT o.*, a.username as operator_username, a.name as operator_name, i.id as item_id, i.quantity, i.price, i.amount, i.product_id, i.product_name FROM orders o LEFT JOIN admin a ON o.operator_id = a.id LEFT JOIN order_item i ON o.id = i.order_id
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.customer_name LIKE CONCAT('%', #{customerName}, '%')
AND o.customer_phone LIKE CONCAT('%', #{customerPhone}, '%')
AND o.status = #{status, typeHandler=com.swiftstock.config.OrderStatusTypeHandler}
AND DATE(o.created_time) >= #{startDate}
AND DATE(o.created_time) <= #{endDate}
ORDER BY o.created_time DESC

mapper.insert:
INSERT INTO orders (
    order_no, customer_name, customer_phone, status, total_amount, 
    remark, created_time, updated_time
) VALUES (
    #{orderNo}, #{customerName}, #{customerPhone}, 
    #{status, typeHandler=com.swiftstock.config.OrderStatusTypeHandler}, 
    #{totalAmount}, #{remark}, #{createdTime}, #{updatedTime}
)

INSERT INTO order_item (
    order_id, product_id, product_name, quantity, price, amount, created_time
) VALUES (
    #{orderId}, #{productId}, #{productName}, #{quantity}, #{price}, #{amount}, #{createdTime}
)
